parameters.jsCode:
function findHeader(headers, name) {
  if (!headers) return '';
  const header = headers.find(h => h.name?.toLowerCase() === name.toLowerCase());
  return header?.value || '';
}

function extractSenderName(from) {
  if (!from) return 'Unknown sender';
  if (from.includes('<')) {
    return from.split('<')[0].replace(/"/g, '').trim() || 'Unknown sender';
  }
  return from;
}

function extractSenderEmail(from) {
  const match = from.match(/<(.+?)>/);
  if (match) return match[1];
  return from;
}

const json = $input.item.json;
const headers = json.payload?.headers || [];

const from = findHeader(headers, 'From') || '';
const subject = findHeader(headers, 'Subject') || 'No subject';
const date = findHeader(headers, 'Date') || '';

const messageId = json.id || '';
const gmailLink = messageId 
  ? `https://mail.google.com/mail/u/0/#inbox/${messageId}` 
  : '';

return {
  json: {
    messageId,
    senderName: extractSenderName(from),
    senderEmail: extractSenderEmail(from),
    subject,
    date,
    snippet: json.snippet || '',
    gmailLink
  }
};

const json = $input.item.json;

const raw = json.output || json.text || json.response || '';

let parsed;

try {
  const cleaned = raw
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();
  parsed = JSON.parse(cleaned);
} catch (error) {
  parsed = {
    shouldNotify: false,
    priority: 'low',
    category: 'other',
    summary: raw.slice(0, 300),
    whyImportant: 'AI parsing failed, review manually',
    suggestedAction: 'Open email and check',
    deadlineOrTime: null,
    discordTitle: 'Email needs manual review'
  };
}

return {
  json: {
    ...json,
    ai: parsed
  }
};
